module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    input clk;
    input rst;
    input sign;
    input [7:0] dividend;
    input [7:0] divisor;
    input opn_valid;
    input res_ready;
    output reg res_valid;
    output reg [15:0] result;
    reg [3:0] cnt;
    reg [16:0] sr;
    reg [7:0] neg_divisor;
    reg [7:0] dividend_abs;
    reg start_cnt;
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            cnt <= 4'b0;
            sr <= 17'b0;
            start_cnt <= 1'b0;
            neg_divisor <= 8'b0;
            dividend_abs <= 8'b0;
        end else begin
            if (opn_valid && cnt == 4'b0) begin
                cnt <= 4'b1;
                start_cnt <= 1'b1;
                if (sign && dividend[7]) dividend_abs <= ~dividend + 1'b1;
                else dividend_abs <= dividend;
                if (sign && divisor[7]) neg_divisor <= ~divisor + 1'b1;
                else neg_divisor <= divisor;
            end
            if (start_cnt) begin
                if (cnt == 4'd8) begin
                    cnt <= 4'b0;
                    start_cnt <= 1'b0;
                    result[15:8] <= sr[15:8];
                    result[7:0] <= sr[7:0];
                end else begin
                    cnt <= cnt + 1'b1;
                    if (neg_divisor[7] == 1'b0 && sr[15:8] >= 8'b10000000) begin
                        sr[15:8] <= sr[15:8] + neg_divisor;
                        sr[0] <= 1'b0;
                    end else if (neg_divisor[7] == 1'b1 && sr[15:8] <= 8'b01111111) begin
                        sr[15:8] <= sr[15:8] + neg_divisor;
                        sr[0] <= 1'b0;
                    end else begin
                        sr[15:8] <= sr[15:8];
                        sr[0] <= 1'b1;
                    end
                    sr[7:0] <= {sr[6:0], sr[7]};
                end
            end
        end
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            res_valid <= 1'b0;
        end else begin
            if (cnt == 4'd8) begin
                res_valid <= 1'b1;
            end else begin
                if (res_valid && res_ready) begin
                    res_valid <= 1'b0;
                end else begin
                    res_valid <= 1'b1;
                end
            end
        end
    end
endmodule
